  9	import type { ValidationMsg } from '@utils/validation/Validation';
 10	
 11	import { getDecodedValue } from './utils/getDecodedValue';
 12	import { openstackSecretFieldValidator } from './utils/openstackSecretFieldValidator';
 13	import type { CredentialsEditModeByTypeProps, onChangeFactoryType } from './utils/types';
 14	import OpenstackRegionEditItem from './OpenstackRegionEditItem';
 15	
 16	const TokenWithUserIDSecretFieldsEditSection: FC<CredentialsEditModeByTypeProps> = ({
 17	  onNewSecretChange,
 18	  secret,
 19	}) => {
 20	  const { t } = useForkliftTranslation();
 21	
 22	  const token = getDecodedValue(secret?.data?.token);
 23	  const userID = getDecodedValue(secret?.data?.userID);
 24	  const projectID = getDecodedValue(secret?.data?.projectID);
 25	  const regionName = getDecodedValue(secret?.data?.regionName);
 26	
 27	  const [passwordHidden, setPasswordHidden] = useState<boolean>(true);
 28	
 29	  const [tokenValidation, setTokenValidation] = useState<ValidationMsg>(
 30	    openstackSecretFieldValidator(OpenstackSecretFieldsId.Token, token!),
 31	  );
 32	
 33	  const [userIDValidation, setUserIdValidation] = useState<ValidationMsg>(
 34	    openstackSecretFieldValidator(OpenstackSecretFieldsId.UserId, userID!),
 35	  );
 36	
 37	  const [projectIDValidation, setProjectIDValidation] = useState<ValidationMsg>(
 38	    openstackSecretFieldValidator(OpenstackSecretFieldsId.ProjectId, projectID!),
 39	  );
 40	
 41	  const [regionNameValidation, setRegionNameValidation] = useState<ValidationMsg>(
 42	    openstackSecretFieldValidator(OpenstackSecretFieldsId.RegionName, regionName!),
 43	  );
 44	
 45	  const handleChange = useCallback(
 46	    (id: OpenstackSecretFieldsId, value: string) => {
 47	      const validationState = openstackSecretFieldValidator(id, value);
 48	
 49	      if (id === OpenstackSecretFieldsId.Token) setTokenValidation(validationState);
 50	      if (id === OpenstackSecretFieldsId.UserId) setUserIdValidation(validationState);
 51	      if (id === OpenstackSecretFieldsId.ProjectId) setProjectIDValidation(validationState);
 52	      if (id === OpenstackSecretFieldsId.RegionName) setRegionNameValidation(validationState);
 53	
 54	      const encodedValue = encode(value?.trim() ?? '');
 55	
 56	      onNewSecretChange({ ...secret, data: { ...secret.data, [id]: encodedValue } });
 57	    },
 58	    [secret, onNewSecretChange],
 59	  );
 60	
 61	  const onClickTogglePassword = () => {
 62	    setPasswordHidden(!passwordHidden);
 63	  };
 64	
 65	  const onChangeFactory: onChangeFactoryType = (changedField) => (_e, value) => {
 66	    handleChange(changedField as OpenstackSecretFieldsId, value);
 67	  };
 68	
 69	  return (
 70	    <>
 71	      <FormGroupWithHelpText
 72	        label={t('Token')}
 73	        isRequired
 74	        fieldId={OpenstackSecretFieldsId.Token}
 75	        helperText={tokenValidation.msg}
 76	        helperTextInvalid={tokenValidation.msg}
 77	        validated={tokenValidation.type}
 78	      >
 79	        <InputGroup>
 80	          <TextInput
 81	            spellCheck="false"
 82	            isRequired
 83	            type={passwordHidden ? 'password' : 'text'}
 84	            id={OpenstackSecretFieldsId.Token}
 85	            name={OpenstackSecretFieldsId.Token}
 86	            value={token}
 87	            onChange={onChangeFactory(OpenstackSecretFieldsId.Token)}
 88	            validated={tokenValidation.type}
 89	          />
 90	          <Button
 91	            variant={ButtonVariant.control}
 92	            onClick={onClickTogglePassword}
 93	            aria-label={passwordHidden ? 'Show password' : 'Hide password'}
 94	          >
 95	            {passwordHidden ? <EyeIcon /> : <EyeSlashIcon />}
 96	          </Button>
 97	        </InputGroup>
 98	      </FormGroupWithHelpText>
 99	
100	      <FormGroupWithHelpText
101	        label={t('User ID')}
102	        isRequired
103	        fieldId={OpenstackSecretFieldsId.UserId}
104	        helperText={userIDValidation.msg}
105	        helperTextInvalid={userIDValidation.msg}
106	        validated={userIDValidation.type}
107	      >
108	        <TextInput
109	          spellCheck="false"
110	          isRequired
111	          type="text"
112	          id={OpenstackSecretFieldsId.UserId}
113	          name={OpenstackSecretFieldsId.UserId}
114	          value={userID}
115	          onChange={onChangeFactory(OpenstackSecretFieldsId.UserId)}
116	          validated={userIDValidation.type}
117	        />
118	      </FormGroupWithHelpText>
119	
120	      <FormGroupWithHelpText
121	        label={t('Project ID')}
122	        isRequired
123	        fieldId={OpenstackSecretFieldsId.ProjectId}
124	        helperText={projectIDValidation.msg}
125	        helperTextInvalid={projectIDValidation.msg}
126	        validated={projectIDValidation.type}
127	      >
128	        <TextInput
129	          spellCheck="false"
130	          isRequired
131	          type="text"
132	          id={OpenstackSecretFieldsId.ProjectId}
133	          name={OpenstackSecretFieldsId.ProjectId}
134	          value={projectID}
135	          onChange={onChangeFactory(OpenstackSecretFieldsId.ProjectId)}
136	          validated={projectIDValidation.type}
137	        />
138	      </FormGroupWithHelpText>
139	
140	      <OpenstackRegionEditItem
141	        regionNameValidation={regionNameValidation}
142	        regionName={regionName}
143	        onChangeFactory={onChangeFactory}
144	      />
145	    </>
146	  );
147	};
148	
149	export default TokenWithUserIDSecretFieldsEditSection;

